{
  "activities": [
    {
      "type": "activity",
      "title": "Role Play and Dramatization",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "Prose/Poetry Collection",
      "details": "Encourage classroom interaction through role play, skits, and dramatization of stories like 'The Adventures of Toto', 'The Happy Prince', or 'The Proposal' to develop communicative competence."
    },
    {
      "type": "activity",
      "title": "Group Discussion on Contemporary Issues",
      "unit_name": "Prose",
      "chapter_name": "Prose",
      "details": "Facilitate discussions on topics from texts like 'Nelson Mandela - Long Walk to Freedom' or 'The Fun They Had' to enable learners to express agreement/disagreement with logic and defend their views."
    },
    {
      "type": "activity",
      "title": "Simulating Real Life Situations",
      "unit_name": "Workbook Units",
      "chapter_name": "Workbook Units",
      "details": "Create situations for students to practice functional language skills, such as writing formal letters or dialogues based on given cues from Workbook Units."
    },
    {
      "type": "activity",
      "title": "Interpreting Visual Inputs",
      "unit_name": "Reading Skills",
      "chapter_name": "Reading Skills",
      "details": "Use newspaper clippings, charts, and graphs to interpret information and discuss issues, enhancing comprehension and analysis skills."
    },
    {
      "type": "activity",
      "title": "Poetry Recitation with Intonation",
      "unit_name": "Poems",
      "chapter_name": "Poems",
      "details": "Practice reading poems effectively with proper rhythm and intonation to develop appreciation for literary devices and enhance oral expression."
    },
    {
      "type": "activity",
      "title": "Narrating Pictorial Stories",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "Prose/Poetry Collection",
      "details": "Ask students to narrate stories depicted pictorially or in non-verbal modes, fostering creativity and storytelling skills."
    },
    {
      "type": "activity",
      "title": "Listening and Speaking Practice",
      "unit_name": "Internal Assessment",
      "chapter_name": "Internal Assessment",
      "details": "Regular practice of listening to authentic audio texts (weather reports, interviews) and retelling them, followed by interactive speaking activities."
    },
    {
      "type": "activity",
      "title": "Debate on Literary Themes",
      "unit_name": "Language through Literature",
      "chapter_name": "Language through Literature",
      "details": "Conduct debates on themes from texts like 'The Sermon at Benares' or 'A Truly Beautiful Mind' to equip learners with skills to articulate points of view."
    }
  ],
  "projects": [
    {
      "title": "Art-Integrated Project: Role Play/Skit",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "Prose/Poetry Collection",
      "details": "Create an art-integrated project based on activities like role play, skit, or dramatization of a selected story (e.g., 'The Last Leaf' or 'The Beggar') to assess listening and speaking skills."
    },
    {
      "title": "Creative Writing Portfolio",
      "unit_name": "Workbook Units",
      "chapter_name": "Workbook Units",
      "details": "Compile a portfolio of creative writing pieces including stories, diary entries, and formal letters based on visual or verbal cues from Workbook Units."
    },
    {
      "title": "Multilingual Literature Appreciation Project",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "Prose/Poetry Collection",
      "details": "Develop sensitivity to Indian languages and literature by comparing themes in prescribed texts with local or regional stories."
    },
    {
      "title": "Media Analysis Project",
      "unit_name": "Reading Skills",
      "chapter_name": "Reading Skills",
      "details": "Analyze newspaper clippings or media inputs to identify issues and present findings through a written report or oral presentation."
    }
  ],
  "practicals": [
    {
      "title": "Listening and Speaking Assessment (ALS)",
      "unit_name": "Internal Assessment",
      "chapter_name": "Internal Assessment",
      "details": "Conduct formal assessment of listening and speaking skills for 5 marks, focusing on interactive competence, fluency, pronunciation, and grammar using a suggested rubric."
    },
    {
      "title": "Graph to Dialogue/Report Transcoding",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Practice transcoding information from graphs/charts into descriptions, reports, dialogues, or short stories to apply writing conventions."
    },
    {
      "title": "Grammar in Context Application",
      "unit_name": "Workbook Units",
      "chapter_name": "Workbook Units",
      "details": "Apply grammatical items like reported speech, modals, and complex sentences in practical exercises such as gap-filling, editing, and transformation."
    },
    {
      "title": "Interactive Competence Exercise",
      "unit_name": "Language through Literature",
      "chapter_name": "Language through Literature",
      "details": "Engage in turn-taking conversations and discussions on literary topics to demonstrate initiation, relevance, and coherence."
    }
  ]
}
